mapper.select:
SELECT o.id, o.application_id, o.offer_time, o.expected_join_date, o.status, o.docs_submitted, o.salary, o.benefits, o.remark, o.create_time, o.update_time, u.real_name AS candidateName, j.title AS jobTitle FROM offer o LEFT JOIN application a ON o.application_id = a.id AND a.deleted = 0 LEFT JOIN job_post j ON a.job_id = j.id AND j.deleted = 0 LEFT JOIN sys_user u ON a.candidate_id = u.id AND u.deleted = 0
AND o.status = #{query.status}
AND u.real_name LIKE CONCAT('%', #{query.candidateName}, '%')
AND a.candidate_id = #{query.candidateId}
ORDER BY o.create_time DESC
